SELECT br.id, br.backup_name AS backupName, br.backup_type AS backupType,
       br.scope, br.file_size AS fileSize, br.file_path AS filePath,
       br.operator_id AS operatorId, br.status, br.remark, br.created_at AS createdAt,
       au.username AS operatorName
FROM backup_records br
LEFT JOIN admin_users au ON br.operator_id = au.id


        AND br.status = #{status}


        AND br.backup_type = #{backupType}


ORDER BY br.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM backup_records


        AND status = #{status}


        AND backup_type = #{backupType}

